func campStatusPill(s string) string {
	switch strings.ToLower(s) {
	case "planning":
		return "bg-muted/10 text-muted"
	case "running":
		return "bg-forest text-white"
	case "paused":
		return "bg-ember/10 text-ember"
	case "ended":
		return "bg-sage/20 text-forest"
	case "cancelled":
		return "bg-rust/10 text-rust"
	default:
		return "bg-muted/10 text-muted"
	}
}

func campStatusLabel(s string) string {
	switch strings.ToLower(s) {
	case "planning":
		return "ĐANG LÊN KẾ HOẠCH"
	case "running":
		return "ĐANG CHẠY"
	case "paused":
		return "TẠM DỪNG"
	case "ended":
		return "KẾT THÚC"
	case "cancelled":
		return "HUỶ"
	default:
		return strings.ToUpper(s)
	}
}

